mapper.select:
select d.id as dish_id, d.name as dish_name, d.pic, d.detail, d.meal_type, d.flavor_tags, frd.departure as route_departure, frd.destination as route_destination, 0 as score, 0 as fallback_level from dish d left join flight_route_dish frd on d.id = frd.dish_id
d.status = 1 and ifnull(d.stock, 0) > 0
and d.meal_type = #{mealType}
and d.flavor_tags like concat('%', #{flavor}, '%')
and (frd.id is null or frd.id in ( select id from flight_route_dish where dish_id = d.id and departure = (select departure from flight_info where id = #{flightId}) and destination = (select destination from flight_info where id = #{flightId}) ))
order by d.id desc limit #{limit}

mapper.update:
update flight_service_rating
set rating_status = 'DEFERRED',
        defer_count = ifnull(defer_count, 0) + 1,
        last_visible_at = #{now},
        next_remind_at = #{nextRemindAt},
        update_time = #{now}
where user_id = #{userId}
    and flight_id = #{flightId}
    and rating_status in ('PENDING', 'DEFERRED')
    and (expire_at is null or expire_at > #{now})

update recommendation_log rl
inner join flight_service_rating fr on fr.source_log_id = rl.id
set rl.user_rating = #{rating}
where fr.user_id = #{userId}
    and fr.flight_id = #{flightId}
    and fr.rating_status = 'SUBMITTED'

mapper.select:
select d.id as dishId, d.name as dishName, count(rl.id) as selectCount from dish d left join recommendation_log rl on ( rl.user_feedback like concat('%dishId=', d.id, '%') or rl.recommended_dishes like concat('%\"', d.name, '\"%') or rl.recommended_dishes like concat('%', d.name, '%') or rl.recommended_dishes regexp concat('(^|[^0-9])', d.id, '([^0-9]|$)') ) and ( rl.user_feedback like 'MANUAL_SELECTED%' or rl.user_feedback like 'AUTO_SELECTED_OVERDUE%' )
and rl.create_time >= #{startTime}
and rl.create_time <= #{endTime}
where d.status = 1 group by d.id, d.name having count(rl.id) > 0 order by selectCount desc, d.id desc limit #{limit}

mapper.update:
update meal_selection
set update_time = #{updateTime}
where user_id = #{userId}
    and flight_id = #{flightId}

update meal_selection
set status = #{status},
    update_time = #{updateTime}
where user_id = #{userId}
  and flight_id = #{flightId}

mapper.select:
select count(1)
from meal_selection
where user_id = #{userId}
  and flight_id = #{flightId}

mapper.update:
update recommendation_log
set user_rating = #{rating}
where id = (
    select id
    from (
        select rl.id
        from recommendation_log rl
        where rl.user_id = #{userId}
          and rl.flight_id = #{flightId}
          and rl.user_feedback like 'MANUAL_SELECTED%'
        order by rl.id desc
        limit 1
    ) latest
)

mapper.select:
select tag
from (
         select case when up.flavor_preferences like '%清淡%' then '清淡党' end as tag
         from user_preference up
         where up.user_id = #{userId}
         union all
         select case when up.flavor_preferences like '%低脂%' then '低脂偏好' end as tag
         from user_preference up
         where up.user_id = #{userId}
         union all
         select case when up.meal_type_preferences like '%1%' then '儿童餐需求' end as tag
         from user_preference up
         where up.user_id = #{userId}
         union all
         select case when up.meal_type_preferences like '%3%' then '清真餐需求' end as tag
         from user_preference up
         where up.user_id = #{userId}
         union all
         select case when count(1) >= 3 then '高频预选用户' end as tag
         from meal_selection ms
         where ms.user_id = #{userId}
     ) t
where tag is not null

mapper.update:
update flight_service_rating
set rating_status = 'EXPIRED',
    update_time = #{now}
where id = #{id}
